mapper.select:
SELECT id, template_code, template_type, name, permission, diagnosis, description, content, creator, status, created_at, updated_at, deleted FROM clinic_medical_template WHERE deleted = 0
AND (template_code LIKE CONCAT('%', #{keyword}, '%') OR name LIKE CONCAT('%', #{keyword}, '%') OR template_type LIKE CONCAT('%', #{keyword}, '%') OR diagnosis LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE clinic_medical_template
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
